var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RADIO_EXTRA_POLICE_NULL","text":{"KOREA":"도주발생. 도주발생.","JPN":"逃走発生。逃走発生。","ENG":"We have a prison break in progress. I repeat, we have a prison break in progress.","TWN":"發生逃獄，發生逃獄。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"RADIO_EXTRA_POLICE_NULL","text":{"KOREA":"제 2 시립교도소에서 수감자가 탈옥했습니다.","JPN":"第2市立刑務所から受刑者が脱獄しました。","ENG":"A prisoner escaped the Second City Penitentiary.","TWN":"第二市立監獄有囚犯越獄。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RADIO_EXTRA_POLICE_NULL","text":{"KOREA":"수감자는 엘릭서를 밀반입하여 각성한 뒤 교도소 벽을 부수고 탈출한 것으로 추정됩니다.","JPN":"受刑者はエリクサーを密かに持ち込み覚醒した後、\\n刑務所の壁を壊して脱出したと推定されます。","ENG":"The suspect is assumed to have smuggled Elixir into the facility and awakened powers before breaking the walls and escaping.","TWN":"推測受刑人是偷渡聖水覺醒後，打破監獄牆壁越獄的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SIREN_POLICE"},{"id":"L5_1","type":"dialog","speaker":"RADIO_EXTRA_POLICE_NULL","text":{"KOREA":"특이사항으로는 보행속도가 차량을 앞설 정도로 빠르다는 점. 체포 시 유의하십시오.","JPN":"特異な点は、歩行速度が車両を追い越すほど速いということです。\\n逮捕の際はご注意ください。","ENG":"Be advised that the suspect can move faster than a car. Please use caution when engaging.","TWN":"特別注意，受刑人的步行速度比車輛還快，逮捕時請小心。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"거기 서라! 범죄자!","JPN":"待て！　犯罪者！","ENG":"Freeze! Criminal!","TWN":"站住！犯罪者！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L7_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"순순히 체포되지 않으면 쓴 맛을 보게 될 거다!","JPN":"大人しく逮捕に応じないと、痛い目に合うから！","ENG":"If you resist arrest, you'll be sorry!","TWN":"如果你不乖乖逮捕歸案的話，可是會吃到苦頭的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRISONER_NPC_NULL_NULL","text":{"KOREA":"흥! 카운터인가 본데, 그래 봐야 내 속도를 따라올 순 없을걸?","JPN":"ふん！　カウンターのようだけど、どうせ俺の速さには追いつけないぞ！","ENG":"Hmph! You're a Counter, eh? Talk all you want, but you'll never be able to catch me!","TWN":"哼！妳看起來雖然是制裁者，但也跟不上我的速度了吧？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING"},{"id":"L11_1","type":"dialog","speaker":"PRISONER_NPC_NULL_NULL","text":{"KOREA":"하하하! 뒤에서 내 엉덩이나 감상하라고 이 느림보야......","JPN":"ははは！　後ろで俺のケツでも鑑賞してろよ、こののろま……","ENG":"Hah hah hah! Just watch my butt as I run to freedom, you slow fool!","TWN":"哈哈哈！妳就在後面欣賞我的屁股吧，妳這隻蝸牛……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRISONER_NPC_NULL_NULL","text":{"KOREA":"우와아악!!!","JPN":"うわああっ！！！","ENG":"Gaaaah!","TWN":"哇啊啊啊！！！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CAR_SKID"},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그렇게 느려서 어디 도망은 치겠니?","JPN":"そんな遅い足で逃げ切れると思った？","ENG":"Aren't you too slow to run away?","TWN":"你速度這麼慢，是想逃到哪裡去呀？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_20"},{"id":"L16_1","type":"dialog","speaker":"PRISONER_NPC_NULL_NULL","text":{"KOREA":"크윽, 어, 어떻게 그런 낡은 경찰차 따위로 날 따라잡은 거지......?","JPN":"くうっ、そ、そのぼろいパトカーでどうやって俺に追いついたんだ……","ENG":"H-how did you catch up with me with that raggedy patrol car?","TWN":"唔，這種老舊警車怎麼可能追得上我……？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이 정도야 간단하지. 경찰청 베스트 드라이버를 얕보지 말라고.","JPN":"このくらい簡単よ。警察庁のベストドライバーを甘く見ないことね。","ENG":"Oh, that was easy. Nothing the best driver in the entire police force can't handle.","TWN":"我可是警察廳的最強車手，不要小看我喔。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK"},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그보다 좀 포기하지 그래? 이제 슬슬 피곤하다, 야.","JPN":"それより、いい加減諦めたらどう？　そろそろ疲れてきたんだけど。","ENG":"Anyway, why don't you give up already? You're really starting to test my patience.","TWN":"話說回來，你現在該放棄了吧？我差不多覺得有點累了，喂。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRISONER_NPC_NULL_NULL","text":{"KOREA":"웃기지 마! 내가 잡힐 것 같아?","JPN":"ふざけるな！　俺が捕まると思うか？","ENG":"Don’t make me laugh! You think you can catch me?","TWN":"開什麼玩笑！妳以為我會被逮住嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRISONER_NPC_NULL_NULL","text":{"KOREA":"더 빨리 달릴 수도 있다고!","JPN":"もっと速く走れるんだぜ！","ENG":"I can run even faster!","TWN":"我還能跑得更快！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"시끄러워! 술래잡기는 끝났다. 범죄자!","JPN":"うるさい！　お遊びもここまでだ、犯罪者！","ENG":"Oh, shut it. No more hide and seek, criminal!","TWN":"吵死了！躲貓貓遊戲已經結束了，犯罪者！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING"},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"변호사 선임하고, 묵비권 행사할 준비나 하시지!","JPN":"弁護士を選任して、黙秘権を行使する準備でもしなさい！","ENG":"Just prepare to hire a lawyer and remain silent!","TWN":"你還是準備請個律師，行使你的沉默權吧！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"오늘도 한 건 했네요. 고생하셨어요.","JPN":"今日もやりましたね。お疲れ様でした。","ENG":"That's another score for today. Good work.","TWN":"今天也解決了一個事件呢，辛苦了。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그나저나 아...... 보고서 쓰기 싫어......","JPN":"それより、ああ……報告書書きたくない……","ENG":"Anyway... Ugh... I really don't want to write another report...","TWN":"不過，啊……我好不想寫報告喔……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"순찰차 박살냈다고 또 한 소리 들을 텐데......","JPN":"パトカーを壊したからまた怒られるだろうな……","ENG":"I'm gonna get an earful for trashing the patrol car again...","TWN":"這次毀了巡邏車，肯定會被罵的……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"嗯……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"응? 왜 그렇게 보세요, 경정님?","JPN":"うん？　警視様、どうしたんですか？","ENG":"Hm? What's that look on your face, Major?","TWN":"嗯？為什麼這麼看著我啊，警正大人。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아, 아니 뭐...... 무능력자도 가끔은 쓸 데가 있다 싶어서.","JPN":"い、いや……無能力者もたまには使い道があるなと思って。","ENG":"W-well, I thought... I thought all cops were the same, but when I look at you, I feel like I was all wrong.","TWN":"沒、沒有，呃……只是覺得無能力者偶爾也很有用。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"오! 방금 칭찬하신 거에요?","JPN":"おお！　今の誉め言葉ですよね？","ENG":"Oooh! Was that a compliment?","TWN":"啊，妳剛才是在讚美我吧？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"더 해줘요! 더!!","JPN":"もっと褒めてください！　もっと！！","ENG":"Please, give me more! More!","TWN":"再多稱讚我一些吧，再多一點'！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"시, 시끄러워!","JPN":"う、うるさい！","ENG":"Sh-shut up!","TWN":"吵、吵死了！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"난 퇴근할 거니까 당신도 집에나 들어가라고!!","JPN":"私は退勤するから、あなたも帰ったらどう？","ENG":"I'm punching out. You should go home now as well!","TWN":"我要下班了，你也給我回家去！！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그러면 좋겠지만 전 보고서를 써야 해서 서로 들어가봐야겠네요.","JPN":"そうしたいところですが、私は報告書を書かなきゃいけないので、まだ帰れないんです。","ENG":"I'd love that, but I'm afraid I have to go back to the office to write up this report.","TWN":"我要寫報告，得回警察廳才行。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그럼 내일 봐요~ 경정님.","JPN":"それでは明日会いましょう、カスカベ警視。","ENG":"See you tomorrow, Major.","TWN":"那麼，明天見囉，警正大人。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"어? 강소영 경위님? 문서보관실에는 언제 들어오셨어요?","JPN":"あれ、マエカワ警部補？　文書保管室にはいつ入られたんですか？","ENG":"Hmm? Lieutenant Kang? What are you doing in the records room?","TWN":"哦？姜素英警衛？妳是什麼時候進檔案室的？"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 하하...... 예전 모범 시말서 양식을 좀 참고할까 해서요.","JPN":"あ、はは……\\n始末書の模範様式をちょっと参考にしようかと思いまして。","ENG":"Ah, hah hah... I just needed a incident report template for reference.","TWN":"啊，哈哈……我是想要參考一下以前優秀的悔過書範本。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"하아, 또 순찰차 한 대 박살내셨나 보네요.","JPN":"なるほど、またパトカーをぶち壊したんですね。","ENG":"*Sigh* Did you wreck another patrol car?","TWN":"唉，看來又有一輛巡邏車被毀掉了吧。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 아무리 경위님이라도 자꾸 허가 없이 들어오시면 곤란합니다.","JPN":"いくら警部補でも許可なく入ってこられたら困りますよ。","ENG":"But Lieutenant, I really can't have you keep coming here without permission.","TWN":"但就算是警衛大人，沒有經過許可就進來，我也會很困擾的。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"허가증 받아서 내일 오세요.","JPN":"許可証をもらって明日出直してください。","ENG":"Come back tomorrow with written permission, please.","TWN":"請明天拿到許可證後再來吧。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네네, 그럼 저는 아무것도 안 건들고 얌전히 돌아가보겠습니다.","JPN":"はいはい、何も触っていませんよ。それじゃあ、大人しく戻りますね。","ENG":"Yeah, yeah. I won't try to be smart and just come back then.","TWN":"是是，那我就什麼都不動，乖乖回去了。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이유미. 카운터 관리국 공인 등급은 A-","JPN":"カスカベ・ユミ。カウンター管理局公認ランクはA。","ENG":"Lee Yumi. Official Administration Counter rating... Grade A-.","TWN":"李悠美，制裁者管理局公認登記為 A-"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"카운터로 추정되는 범죄자의 주거지 침입 사건으로 인해 양친 사망 및 중상을 입음.","JPN":"カウンターと推定される犯罪者の住居侵入事件により両親が死亡し、本人も重傷を負う。","ENG":"Lost both her parents and sustained severe injuries during a B&E by a suspect speculated to be a Counter.","TWN":"推測為制裁者罪犯入侵居所後……失去了雙親，並受到了重傷。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"집이 전소된 뒤로 보호시설에서 생활 중 각성.","JPN":"自宅が全焼し、保護施設で生活していたところ覚醒。","ENG":"Attained her powers while staying at a hospice after her house burned down.","TWN":"房子被燒掉後，在保護設施的生活中覺醒。"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"특이사항으로는, 언니가 사건 직후로 행방불명이라......","JPN":"特異事項は、姉が事件直後に行方不明になったか……","ENG":"Of note, her older sister went missing immediately after the incident...","TWN":"特異點是姐姐在發生事件後行蹤不明……"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"DATABASE_02","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};